# contextifier/services/tag_service.py
"""
TagService — Unified Structural Tag Generation

Replaces the old PageTagProcessor with a single service that generates
ALL structural tags: page, slide, sheet, image, chart, metadata.

Fixes from old code:
- Old PageTagProcessor had asymmetric create_sheet_tag(str) vs create_tag(int)
- Image tags were generated by ImageProcessor, not the tag service
- Chart tags were generated by ChartProcessor separately
- Metadata tags were handled by MetadataFormatter independently
- No single place to get tag patterns for chunking
"""

from __future__ import annotations

import re
import logging
from typing import List, Optional, Tuple

from contextifier.config import ProcessingConfig, TagConfig
from contextifier.types import TagType


class TagService:
    """
    Generates and parses all structural tags in extracted text.

    Provides a unified interface for:
    - Creating tags (page, slide, sheet)
    - Building regex patterns for tag detection
    - Finding tags in text
    - Removing tags from text

    Thread-safe: no mutable state after __init__.
    """

    def __init__(self, config: ProcessingConfig) -> None:
        self._config = config
        self._tag_config: TagConfig = config.tags
        self._logger = logging.getLogger("contextifier.services.tag")

        # Pre-compile patterns
        self._page_pattern = self._build_pattern(
            self._tag_config.page_prefix,
            self._tag_config.page_suffix,
            capture_type="int",
        )
        self._slide_pattern = self._build_pattern(
            self._tag_config.slide_prefix,
            self._tag_config.slide_suffix,
            capture_type="int",
        )
        self._sheet_pattern = self._build_pattern(
            self._tag_config.sheet_prefix,
            self._tag_config.sheet_suffix,
            capture_type="str",
        )
        self._image_pattern = self._build_pattern(
            self._tag_config.image_prefix,
            self._tag_config.image_suffix,
            capture_type="str",
        )

    # ── Tag Creation ──────────────────────────────────────────────────────

    def create_page_tag(self, page_number: int) -> str:
        """Create a page number tag. E.g., '[Page Number: 1]'"""
        return f"{self._tag_config.page_prefix}{page_number}{self._tag_config.page_suffix}"

    def create_slide_tag(self, slide_number: int) -> str:
        """Create a slide number tag. E.g., '[Slide Number: 1]'"""
        return f"{self._tag_config.slide_prefix}{slide_number}{self._tag_config.slide_suffix}"

    def create_sheet_tag(self, sheet_name: str) -> str:
        """Create a sheet name tag. E.g., '[Sheet: Sheet1]'"""
        return f"{self._tag_config.sheet_prefix}{sheet_name}{self._tag_config.sheet_suffix}"

    def create_image_tag(self, image_path: str) -> str:
        """Create an image reference tag. E.g., '[Image:path/to/img.png]'"""
        return f"{self._tag_config.image_prefix}{image_path}{self._tag_config.image_suffix}"

    def create_chart_open_tag(self) -> str:
        """Chart block opening tag. E.g., '[chart]'"""
        return self._tag_config.chart_prefix

    def create_chart_close_tag(self) -> str:
        """Chart block closing tag. E.g., '[/chart]'"""
        return self._tag_config.chart_suffix

    def create_metadata_open_tag(self) -> str:
        """Metadata block opening tag. E.g., '[Document-Metadata]'"""
        return self._tag_config.metadata_prefix

    def create_metadata_close_tag(self) -> str:
        """Metadata block closing tag. E.g., '[/Document-Metadata]'"""
        return self._tag_config.metadata_suffix

    # ── Pattern Access ────────────────────────────────────────────────────

    @property
    def page_pattern(self) -> re.Pattern:
        """Compiled regex pattern for page tags."""
        return self._page_pattern

    @property
    def slide_pattern(self) -> re.Pattern:
        """Compiled regex pattern for slide tags."""
        return self._slide_pattern

    @property
    def sheet_pattern(self) -> re.Pattern:
        """Compiled regex pattern for sheet tags."""
        return self._sheet_pattern

    @property
    def image_pattern(self) -> re.Pattern:
        """Compiled regex pattern for image tags."""
        return self._image_pattern

    def get_pattern_string(self, tag_type: TagType) -> str:
        """Get the regex pattern string for a tag type."""
        patterns = {
            TagType.PAGE: self._page_pattern.pattern,
            TagType.SLIDE: self._slide_pattern.pattern,
            TagType.SHEET: self._sheet_pattern.pattern,
        }
        return patterns.get(tag_type, "")

    # ── Tag Detection ─────────────────────────────────────────────────────

    def find_page_tags(self, text: str) -> List[Tuple[int, int, int]]:
        """Find all page tags. Returns [(start, end, page_number), ...]"""
        return self._find_int_tags(text, self._page_pattern)

    def find_slide_tags(self, text: str) -> List[Tuple[int, int, int]]:
        """Find all slide tags. Returns [(start, end, slide_number), ...]"""
        return self._find_int_tags(text, self._slide_pattern)

    def find_sheet_tags(self, text: str) -> List[Tuple[int, int, str]]:
        """Find all sheet tags. Returns [(start, end, sheet_name), ...]"""
        return [
            (m.start(), m.end(), m.group(1))
            for m in self._sheet_pattern.finditer(text)
        ]

    def has_page_markers(self, text: str) -> bool:
        """Check if text contains any page tags."""
        return bool(self._page_pattern.search(text))

    def has_slide_markers(self, text: str) -> bool:
        """Check if text contains any slide tags."""
        return bool(self._slide_pattern.search(text))

    def has_sheet_markers(self, text: str) -> bool:
        """Check if text contains any sheet tags."""
        return bool(self._sheet_pattern.search(text))

    # ── Tag Removal ───────────────────────────────────────────────────────

    def remove_page_markers(self, text: str) -> str:
        """Remove all page tags from text."""
        return self._page_pattern.sub("", text)

    def remove_slide_markers(self, text: str) -> str:
        """Remove all slide tags from text."""
        return self._slide_pattern.sub("", text)

    def remove_all_structural_markers(self, text: str) -> str:
        """Remove all page, slide, and sheet tags."""
        text = self._page_pattern.sub("", text)
        text = self._slide_pattern.sub("", text)
        text = self._sheet_pattern.sub("", text)
        return text

    # ── Private Helpers ───────────────────────────────────────────────────

    @staticmethod
    def _build_pattern(
        prefix: str,
        suffix: str,
        *,
        capture_type: str = "str",
    ) -> re.Pattern:
        """Build a regex pattern from prefix/suffix."""
        esc_prefix = re.escape(prefix)
        esc_suffix = re.escape(suffix)
        if capture_type == "int":
            return re.compile(rf"{esc_prefix}(\d+){esc_suffix}")
        else:
            return re.compile(rf"{esc_prefix}([^{re.escape(suffix[0])}]+){esc_suffix}")

    @staticmethod
    def _find_int_tags(text: str, pattern: re.Pattern) -> List[Tuple[int, int, int]]:
        """Find all integer-valued tags."""
        results = []
        for m in pattern.finditer(text):
            try:
                value = int(m.group(1))
                results.append((m.start(), m.end(), value))
            except (ValueError, IndexError):
                continue
        return results


__all__ = ["TagService"]
